description:
Content control object.

## Try it

 ```js document-builder={"documentType": "pdf"}
var oContentControl = {
    "Tag": "Document",
    "Id": 0,
    "Lock": 0,
    "InternalId": "1_713"
};
```

A value that defines if it is possible to delete and/or edit the content control or not:* **0** - only deleting* **1** - disable deleting or editing* **2** - only editing* **3** - full access

## Try it

 ```js document-builder={"documentType": "pdf"}
var arrDocuments = [{
    "Props": {
        "Id": 100,
        "Tag": "CC_Tag",
        "Lock": 3
    },
    "Script": "var oParagraph = Api.CreateParagraph();oParagraph.AddText('Hello world!');Api.GetDocument().InsertContent([oParagraph]);"
}];
window.Asc.plugin.executeMethod("InsertAndReplaceContentControls", [arrDocuments]);
```

Returns information about all the forms that have been added to the document.

## Try it

 ```js document-builder={"documentType": "pdf"}
window.Asc.plugin.executeMethod ("GetAllForms", null, function (data) {
    for (var i = 0; i < data.length; i++) {
        if (data[i].Tag == 11) {
            this.Asc.plugin.executeMethod ("SelectContentControl", [data[i].InternalId]);
            break;
        }
    }
});
```

